/* ------------------------------------------------------------------ */
/*  Render order – city-states drawn last so they sit on top           */
/* ------------------------------------------------------------------ */
const CITY_STATES = new Set(["BE", "HB", "HH"]);

/* Maps each city-state to its enclosing parent state */
const CITY_STATE_PARENT: Record<string, string> = {
  BE: "BB",
  HB: "NI",
  HH: "SH",
};

/* Parent states whose "top" tooltip would cover a city-state.
   These get right/left placement instead, like the city-states themselves. */
const PARENT_SIDE_PLACEMENT = new Set(["NI"]);

const RENDER_ORDER = [
  ...Object.keys(STATE_PATHS).filter((c) => !CITY_STATES.has(c)),
  ...Object.keys(STATE_PATHS).filter((c) => CITY_STATES.has(c)),
];

/* ------------------------------------------------------------------ */
/*  Types & Props                                                      */
/* ------------------------------------------------------------------ */
interface GermanyMapProps {
  translations: Record<string, string>;
  states: Array<{ name: string; code: string; capital: string }>;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */
export default function GermanyMap({
  translations: t,
  states,
}: GermanyMapProps) {
  const [hoveredState, setHoveredState] = useState<string | null>(null);
  const [selectedState, setSelectedState] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const tooltipTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  /* Track the last hovered state so we can detect city→parent transitions */
  const lastHoveredRef = useRef<string | null>(null);
  const router = useRouter();

  const stateMap = new Map(states.map((s) => [s.code, s]));

  /* close popup on outside click */
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (
        containerRef.current &&
        !containerRef.current.contains(e.target as Node)
      ) {
        setSelectedState(null);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  /* close popup on Escape */
  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") {
        setSelectedState(null);
      }
    }
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, []);

  /* Convert SVG label coordinates to container-relative % and determine
     tooltip placement. City-states and parent states that would cover a
     city-state get side placement so the tooltip doesn't obstruct. */
  const getTooltipPosition = useCallback((code: string) => {
    const entry = STATE_PATHS[code];
    if (!entry) return { left: "50%", top: "50%", placement: "top" as const };
    // viewBox is 0 0 585 720
    const leftPct = (entry.labelX / 585) * 100;
    const topPct = (entry.labelY / 720) * 100;

    // City-states and parents whose tooltip would cover a city-state
    // get side placement to keep the city-state accessible
    if (CITY_STATES.has(code) || PARENT_SIDE_PLACEMENT.has(code)) {
      // Place right unless too close to the right edge (>75%)
      const placement = leftPct > 75 ? "left" : "right";
      return { left: `${leftPct}%`, top: `${topPct}%`, placement };
    }

    return { left: `${leftPct}%`, top: `${topPct}%`, placement: "top" as const };
  }, []);

  const handleClick = (code: string) => {
    if (selectedState === code) {
      setSelectedState(null);
    } else {
      setSelectedState(code);
    }
  };

  const handleMouseEnter = (code: string) => {
    if (tooltipTimeoutRef.current) {
      clearTimeout(tooltipTimeoutRef.current);
      tooltipTimeoutRef.current = null;
    }

    const prev = lastHoveredRef.current;

    /* If the user was just hovering a city-state and now enters its
       parent state (e.g. BE → BB), it means the mouse is crossing the
       parent on its way to the tooltip. In that case, keep showing the
       city-state tooltip instead of switching to the parent. */
    if (
      prev &&
      CITY_STATES.has(prev) &&
      CITY_STATE_PARENT[prev] === code
    ) {
      // Don't switch – keep the city-state active
      return;
    }

    lastHoveredRef.current = code;
    setHoveredState(code);
  };

  const handleMouseLeave = () => {
    if (tooltipTimeoutRef.current) {
      clearTimeout(tooltipTimeoutRef.current);
    }
    tooltipTimeoutRef.current = setTimeout(() => {
      lastHoveredRef.current = null;
      setHoveredState(null);
    }, 150);
  };

  /* When hovering the tooltip itself, cancel the hide timeout */
  const handleTooltipMouseEnter = () => {
    if (tooltipTimeoutRef.current) {
      clearTimeout(tooltipTimeoutRef.current);
      tooltipTimeoutRef.current = null;
    }
  };

  const handleTooltipMouseLeave = () => {
    tooltipTimeoutRef.current = setTimeout(() => {
      lastHoveredRef.current = null;
      setHoveredState(null);
    }, 150);
  };

  const activeCode = selectedState ?? hoveredState;
  const activeState = activeCode ? stateMap.get(activeCode) : null;
  const activePos = activeCode ? getTooltipPosition(activeCode) : null;

  return (
    <div ref={containerRef} className="relative w-full max-w-lg mx-auto">
      <svg
        ref={svgRef}
        viewBox="0 0 585 720"
        className="w-full h-auto"
        role="img"
        aria-label={t.map_section_title}
      >
        {RENDER_ORDER.map((code) => {
          const { paths, labelX, labelY } = STATE_PATHS[code];
          const state = stateMap.get(code);
          const isActive = activeCode === code;
          return (
            <g
              key={code}
              onClick={() => handleClick(code)}
              onMouseEnter={() => handleMouseEnter(code)}
              onMouseLeave={handleMouseLeave}
              className="cursor-pointer"
              role="button"
              tabIndex={0}
              aria-label={state?.name ?? code}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  handleClick(code);
                }
              }}
            >
              {paths.map((d, i) => (
                <path
                  key={i}
                  d={d}
                  className={`transition-all duration-200 ${
                    isActive
                      ? "fill-primary/80 stroke-primary-600 dark:fill-primary/60 dark:stroke-primary-300"
                      : "fill-foreground/[0.06] stroke-foreground/20 dark:fill-foreground/[0.10] dark:stroke-foreground/15"
                  }`}
                  strokeWidth={isActive ? "2" : "1"}
                  strokeLinejoin="round"
                />
              ))}
              <text
                x={labelX}
                y={labelY}
                textAnchor="middle"
                dominantBaseline="central"
                className={`text-[10px] font-bold pointer-events-none select-none transition-colors duration-200 ${
                  isActive
                    ? "fill-primary-foreground dark:fill-white"
                    : "fill-foreground/40"
                }`}
              >
                {code}
              </text>
            </g>
          );
        })}
      </svg>

      {/* Tooltip / Popup – anchored to state label center */}
      {activeState && activePos && (
        <div
          className="absolute z-50 pointer-events-auto"
          style={{
            left: activePos.left,
            top: activePos.top,
            transform:
              activePos.placement === "right"
                ? "translate(12px, -50%)"
                : activePos.placement === "left"
                  ? "translate(calc(-100% - 12px), -50%)"
                  : "translate(-50%, -100%)",
          }}
          onMouseEnter={handleTooltipMouseEnter}
          onMouseLeave={handleTooltipMouseLeave}
        >
          {/* Invisible bridge – fills gap between tooltip card and state.
              For side placement, horizontal bridge; for top, vertical bridge. */}
          <div
            className={
              activePos.placement === "top"
                ? "pb-3"
                : activePos.placement === "right"
                  ? "pl-3"
                  : "pr-3"
            }
          >
            <div className="glass-card rounded-2xl px-4 py-3 shadow-2xl border border-default-200 dark:border-default-100 min-w-[200px] max-w-[260px]">
              {/* State flag + name */}
              <div className="flex items-center gap-2.5">
                <Image
                  src={`/states/flag/${activeState.name}.svg`}
                  alt={activeState.name}
                  width={28}
                  height={20}
                  className="rounded-sm border border-default-200 object-cover"
                />
                <div className="min-w-0">
                  <p className="font-bold text-sm text-foreground leading-tight truncate">
                    {activeState.name}
                  </p>
                  {activeState.capital && (
                    <p className="text-xs text-default-500 leading-tight">
                      {activeState.capital}
                    </p>
                  )}
                </div>
              </div>

              {/* Action buttons */}
              <div className="flex flex-col gap-1.5 mt-3">
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    router.push(
                      `/pruefstellen/${activeState.code.toUpperCase()}`
                    );
                  }}
                  className="flex items-center gap-2 w-full px-3 py-2 rounded-lg text-xs font-semibold transition-colors bg-primary/10 hover:bg-primary/20 text-primary"
                >
                  {/* Map pin icon */}
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    width="14"
                    height="14"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    aria-hidden="true"
                    className="shrink-0"
                  >
                    <path d="M20 10c0 4.993-5.539 10.193-7.399 11.799a1 1 0 0 1-1.202 0C9.539 20.193 4 14.993 4 10a8 8 0 0 1 16 0" />
                    <circle cx="12" cy="10" r="3" />
                  </svg>
                  {t.map_tooltip_centers}
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    router.push(
                      `/question-catalogue/${activeState.code.toUpperCase()}`
                    );
                  }}
                  className="flex items-center gap-2 w-full px-3 py-2 rounded-lg text-xs font-semibold transition-colors bg-secondary/10 hover:bg-secondary/20 text-secondary-600 dark:text-secondary-400"
                >
                  {/* Book icon */}
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    width="14"
                    height="14"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    aria-hidden="true"
                    className="shrink-0"
                  >
                    <path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1 0-5H20" />
                  </svg>
                  {t.map_tooltip_questions}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
